INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('acetaminophen', 'Acetaminophen', 'Tylenol', 'Non-opioid analgesic / antipyretic', 'Centrally inhibits prostaglandin synthesis; minimal anti-inflammatory effect.', 'Mild-to-moderate pain, fever reduction.', 'Severe hepatic impairment, hypersensitivity.', 'Hepatotoxicity with doses >4g/day or chronic alcohol use.', 'LFTs (baseline + with chronic use), acetaminophen level if overdose suspected', 'Max 3-4g/day in healthy adults; max 2g/day with liver disease or chronic alcohol. Read combo product labels.', 'Antidote: N-acetylcysteine (NAC). Check all OTC and combo Rx for hidden acetaminophen.', 'analgesic,antipyretic,hepatotoxicity,nac,overdose,pain,fever', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('albuterol', 'Albuterol', 'Ventolin, ProAir, Proventil', 'Short-acting beta-2 agonist bronchodilator', 'Selective beta-2 agonism relaxes bronchial smooth muscle.', 'Acute bronchospasm in asthma/COPD, exercise-induced bronchospasm.', 'Hypersensitivity. Caution with cardiac dysrhythmias and severe HTN.', NULL, 'Potassium (can drop with high doses), glucose (can rise)', 'Rescue inhaler - take 5-15 min before exercise if prescribed. Rinse mouth after. Notify provider if needing >2x/week (poor control).', 'Watch for tachycardia, tremors, restlessness. Severe asthma may need continuous neb. Spacer improves delivery.', 'bronchodilator,asthma,copd,bronchospasm,respiratory,beta_agonist', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('azathioprine', 'Azathioprine', 'Imuran, Azasan', 'Purine antimetabolite immunosuppressant', 'Metabolized to 6-mercaptopurine which inhibits purine synthesis → blocks lymphocyte proliferation.', 'Transplant rejection, severe RA, inflammatory bowel disease, lupus nephritis.', 'Pregnancy (some forms), TPMT deficiency, severe infection.', 'Increased risk of lymphoma and skin cancer.', 'CBC (especially WBC), LFTs, TPMT genotype, amylase/lipase', 'Take with food to reduce GI upset. Avoid live vaccines. Use sun protection. Report sore throat, fever, easy bruising.', 'Allopurinol increases toxicity (reduce dose 75%). Monitor for myelosuppression and pancreatitis.', 'immunosuppressant,transplant,myelosuppression,lymphoma,allopurinol,ibd', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('carbamazepine', 'Carbamazepine', 'Tegretol, Carbatrol', 'Iminostilbene anticonvulsant / mood stabilizer', 'Sodium channel blockade reducing repetitive neuronal firing.', 'Partial seizures, trigeminal neuralgia, bipolar disorder.', 'Bone marrow suppression, MAOI use within 14 days, hypersensitivity to TCAs.', 'Stevens-Johnson syndrome (HLA-B*1502 in Asian ancestry), aplastic anemia, agranulocytosis.', 'Carbamazepine level (4-12 mcg/mL), CBC, LFTs, sodium (SIADH), HLA-B*1502 in at-risk ethnicities', 'Take with food. Report rash, fever, easy bruising, dark urine. Avoid grapefruit. Use sunscreen.', 'Auto-induces own metabolism. Many CYP interactions. SIADH risk - monitor sodium.', 'anticonvulsant,seizure,trigeminal_neuralgia,stevens_johnson,siadh,bipolar,neurology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('cisplatin', 'Cisplatin', 'Platinol', 'Platinum-based antineoplastic', 'Crosslinks DNA strands, inhibiting replication and triggering apoptosis.', 'Testicular, ovarian, bladder, lung, head/neck cancers.', 'Significant renal impairment, hearing loss, peripheral neuropathy.', 'Severe nephrotoxicity, ototoxicity, myelosuppression, anaphylaxis.', 'Creatinine, magnesium, potassium, CBC, audiometry', 'Drink plenty of fluids. Report hearing changes, tingling in hands/feet, decreased urine.', 'Pre-hydrate with IV fluids + mannitol. Antiemetic prophylaxis (5-HT3 + dexamethasone). Monitor creatinine daily.', 'chemo,antineoplastic,nephrotoxicity,ototoxicity,oncology,nausea', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('cyclosporine', 'Cyclosporine', 'Sandimmune, Neoral, Gengraf', 'Calcineurin inhibitor immunosuppressant', 'Inhibits calcineurin → blocks T-cell activation and IL-2 production.', 'Solid organ transplant rejection prevention, severe psoriasis, RA.', 'Uncontrolled HTN, malignancy, concurrent live vaccines.', 'Lymphoma and skin malignancies, severe infection, nephrotoxicity, infusion reactions.', 'Cyclosporine trough level, creatinine, magnesium, potassium, BP', 'Take exactly at same times. Avoid grapefruit juice. Avoid live vaccines. Use sun protection. Report tremor, swelling, decreased urine.', 'Many drug interactions (CYP3A4). Monitor for nephrotoxicity, gingival hyperplasia, hirsutism. No grapefruit.', 'immunosuppressant,transplant,nephrotoxicity,grapefruit,cyp3a4,calcineurin', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('digoxin', 'Digoxin', 'Lanoxin', 'Cardiac glycoside', 'Inhibits Na+/K+ ATPase, increasing intracellular Ca++ and inotropy; slows AV conduction.', 'Chronic CHF, atrial fibrillation rate control.', 'V-fib, hypersensitivity, 2nd/3rd degree AV block without pacing.', NULL, 'Digoxin level (0.5-2 ng/mL therapeutic), potassium, magnesium, creatinine', 'Take same time daily. Check pulse for 1 full minute - hold for HR<60. Report nausea, vision changes (yellow-green halos).', 'Antidote: digoxin immune Fab (Digibind). Hypokalemia potentiates toxicity. Hold for apical HR<60.', 'digoxin,chf,afib,toxicity,hypokalemia,bradycardia,cardiology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('donepezil', 'Donepezil', 'Aricept', 'Cholinesterase inhibitor (Alzheimer''s)', 'Reversibly inhibits acetylcholinesterase → increases ACh in brain, improving cognition.', 'Mild to severe Alzheimer''s dementia.', 'Hypersensitivity to piperidines.', NULL, 'Weight, heart rate, EKG (QT)', 'Take at bedtime. Modest benefit - won''t reverse disease. Report fainting, abnormal heartbeat, GI bleeding.', 'Bradycardia and syncope risk. GI side effects (nausea, diarrhea) common at start. Weight loss possible.', 'alzheimers,dementia,cholinesterase,bradycardia,neurology,geriatric', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('ethinyl-norgestimate', 'Ethinyl estradiol / norgestimate', 'Ortho Tri-Cyclen, TriNessa', 'Combined oral contraceptive (estrogen + progestin)', 'Suppresses ovulation via negative feedback on FSH/LH; thickens cervical mucus.', 'Contraception, acne, menstrual regulation.', 'Pregnancy, smokers >35, history of VTE/stroke/MI, breast cancer, active liver disease, uncontrolled HTN.', 'Cardiovascular events in smokers >35.', 'Blood pressure, lipid panel, liver enzymes', 'Take at same time daily. Use backup method first cycle. ACHES warning signs: Abdominal pain, Chest pain, Headaches, Eye changes, Severe leg pain.', 'Screen for smoking + clot history. No effect on STI prevention. Antibiotics may reduce effectiveness.', 'contraceptive,estrogen,progestin,vte,smoking,reproductive,maternity', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('furosemide', 'Furosemide', 'Lasix', 'Loop diuretic', 'Blocks Na/K/2Cl cotransporter in thick ascending loop of Henle.', 'Acute pulmonary edema, CHF exacerbation, edema, hypertension, hypercalcemia.', 'Anuria, severe hypovolemia, sulfa allergy (relative).', NULL, 'Potassium (often low), sodium, BUN/creatinine, magnesium', 'Take in morning. Rise slowly (orthostasis). Increase K+ foods unless on K-sparing. Report cramps/weakness.', 'IV push slowly (max 20 mg/min) to avoid ototoxicity. Daily weights. Strict I&Os.', 'diuretic,chf,pulmonary_edema,hypokalemia,fluid_overload,cardiology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('heparin', 'Heparin', 'Hep-Lock', 'Anticoagulant', 'Potentiates antithrombin III; inactivates thrombin and Factor Xa.', 'DVT/PE prophylaxis and treatment, acute MI, atrial fibrillation, dialysis circuits.', 'Active bleeding, HIT, severe thrombocytopenia, recent neurosurgery/spinal anesthesia.', 'Spinal/epidural hematoma risk with neuraxial anesthesia; HIT can be fatal.', 'aPTT (therapeutic 1.5-2.5x baseline), platelets, hemoglobin/hematocrit', 'Use soft toothbrush + electric razor. Report unusual bruising, dark stools, headache.', 'Antidote: protamine sulfate. Monitor for HIT after 5-10 days. Hold for invasive procedures.', 'anticoagulant,dvt,pe,bleeding,hit,cardiology,hematology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('insulin-regular', 'Insulin regular (rapid-acting / IV)', 'Humulin R, Novolin R', 'Antidiabetic - rapid-acting insulin', 'Activates insulin receptor to drive glucose into cells; only insulin safe to give IV.', 'DKA, HHS, hyperkalemia (with D50), tight glycemic control in critical care.', 'Hypoglycemia. Use caution with renal/hepatic impairment.', 'Risk of severe hypoglycemia, especially with IV infusion.', 'Glucose, potassium, A1C, BMP', 'Rotate injection sites. Recognize hypoglycemia (shaking, sweating, confusion). Carry fast-acting glucose.', 'Onset 30 min SC, 5 min IV. Peak 2-4 hr SC. Always verify dose with second RN. Never mix insulin types when IV.', 'diabetes,dka,hyperkalemia,glucose,hypoglycemia,endocrine,critical_care', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('lactated-ringers', 'Lactated Ringer''s', 'LR, Hartmann''s solution', 'Isotonic balanced IV crystalloid', 'Provides volume + electrolytes (Na, K, Ca, Cl, lactate); lactate converted to bicarbonate buffers acidemia.', 'Volume resuscitation (especially burns, surgery), mild metabolic acidosis.', 'Liver failure (cannot metabolize lactate), severe hyperkalemia, lactic acidosis.', NULL, 'Potassium, calcium, sodium, lactate', 'Replaces lost body fluids. Report swelling or trouble breathing.', 'Do not co-administer with ceftriaxone (calcium precipitate). Watch for fluid overload + hyperkalemia in renal failure.', 'iv_fluids,burns,surgery,resuscitation,crystalloid,acidosis', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('levetiracetam', 'Levetiracetam', 'Keppra', 'SV2A modulator anticonvulsant', 'Binds synaptic vesicle protein SV2A, modulating neurotransmitter release. Mechanism partly unclear.', 'Partial-onset, myoclonic, and tonic-clonic seizures (adjunctive or monotherapy).', 'Hypersensitivity. Caution in renal impairment.', NULL, 'Creatinine (dose adjust), CBC (rare neutropenia)', 'Take consistently. Report behavioral changes, depression, suicidal thoughts.', 'Well tolerated overall. Watch for irritability/agitation, especially pediatrics. Adjust for renal function.', 'anticonvulsant,seizure,keppra,depression,renal_dosing,neurology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('levodopa-carbidopa', 'Levodopa / carbidopa', 'Sinemet', 'Dopamine precursor (antiparkinsonian)', 'Levodopa crosses BBB and is converted to dopamine. Carbidopa blocks peripheral conversion to reduce side effects.', 'Parkinson''s disease, parkinsonism symptoms.', 'Narrow-angle glaucoma, melanoma, MAOI within 14 days.', NULL, 'CBC, LFTs (long-term)', 'May take weeks for effect. Do not take with high-protein meals (compete for absorption). Don''t stop abruptly. May cause dark sweat/urine - harmless.', 'Monitor for ''on-off'' phenomenon and dyskinesias. Orthostatic hypotension common. Avoid pyridoxine without carbidopa.', 'parkinsons,dopamine,levodopa,on_off,dyskinesia,orthostatic,neurology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('lidocaine', 'Lidocaine', 'Xylocaine', 'Class IB antiarrhythmic / local anesthetic', 'Blocks fast sodium channels; shortens action potential and refractory period in ventricular tissue.', 'Ventricular dysrhythmias (V-tach with pulse, V-fib), local/regional anesthesia.', 'AV block (without pacing), Stokes-Adams syndrome, hypersensitivity.', NULL, 'Lidocaine level (1.5-5 mcg/mL), liver function (metabolism)', 'If used for procedure, area will be numb. Report any chest pain, dizziness, or tingling around mouth.', 'Toxicity: tinnitus, perioral numbness, seizures. Cardiac monitor with IV infusion. Reduce dose in elderly and liver failure.', 'antiarrhythmic,local_anesthetic,vtach,vfib,toxicity,cardiology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('lisinopril', 'Lisinopril', 'Prinivil, Zestril', 'ACE inhibitor', 'Blocks conversion of angiotensin I to II, reducing vasoconstriction and aldosterone release.', 'Hypertension, CHF, post-MI, diabetic nephropathy.', 'Pregnancy (Category D), bilateral renal artery stenosis, angioedema history.', 'Pregnancy - fetal injury and death.', 'Potassium (can rise), creatinine, BUN', 'Report persistent dry cough or facial/throat swelling immediately. Avoid K+ supplements/salt substitutes.', 'First-dose hypotension - monitor BP for 4 hr. Hold for SBP<90. Watch for angioedema and hyperkalemia.', 'ace_inhibitor,hypertension,chf,pregnancy,angioedema,hyperkalemia,cardiology', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('magnesium-sulfate-ob', 'Magnesium sulfate (OB)', 'MgSO4', 'Anticonvulsant / tocolytic / electrolyte', 'CNS depressant via NMDA antagonism; smooth muscle relaxation.', 'Preeclampsia/eclampsia seizure prophylaxis, preterm labor tocolysis, torsades de pointes.', 'Heart block, myasthenia gravis, severe renal failure.', NULL, 'Magnesium level (therapeutic 4-7 mEq/L for OB), creatinine, calcium', 'Will feel warm and flushed. Report difficulty breathing or muscle weakness.', 'Antidote: calcium gluconate. Assess DTRs, RR, urine output q1h. Magnesium toxicity: loss of DTRs (first), respiratory depression, cardiac arrest.', 'preeclampsia,eclampsia,seizure,tocolytic,magnesium_toxicity,calcium_gluconate,maternity,obstetrics', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('medroxyprogesterone', 'Medroxyprogesterone (depot)', 'Depo-Provera', 'Progestin-only contraceptive (long-acting)', 'Suppresses ovulation; thickens cervical mucus; thins endometrium.', 'Long-acting contraception, endometriosis, abnormal uterine bleeding.', 'Pregnancy, undiagnosed vaginal bleeding, breast cancer, severe liver disease.', 'Bone mineral density loss with long-term use - limit to 2 years if possible.', 'Bone density (DEXA), weight, blood pressure', 'IM injection every 12 weeks. Take calcium and vitamin D. Fertility return may delay 12-18 months after discontinuation.', 'Z-track or deep IM. Do not massage site. Counsel on weight gain, irregular bleeding, mood changes.', 'contraceptive,progestin,depo,bone_density,reproductive,maternity', 'published', unixepoch())
