INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('methotrexate-oncology', 'Methotrexate (high-dose)', 'Trexall, Otrexup', 'Antimetabolite chemotherapy / DMARD', 'Inhibits dihydrofolate reductase, blocking DNA/RNA synthesis. Folic acid antagonist.', 'Leukemia, lymphoma, rheumatoid arthritis, psoriasis, ectopic pregnancy.', 'Pregnancy (Category X), severe renal/hepatic impairment, bone marrow suppression.', 'Hepatotoxicity, severe myelosuppression, pulmonary toxicity, fatal if misdosed (weekly vs daily).', 'CBC, creatinine, LFTs, methotrexate level (high-dose)', 'Take EXACTLY as prescribed - typically weekly for arthritis. Reliable contraception. Report mouth sores, cough, jaundice.', 'Rescue: leucovorin (folinic acid). Verify weekly vs daily dosing with pharmacy. Monitor for stomatitis, hepatotoxicity.', 'chemo,antimetabolite,methotrexate,oncology,rheumatoid_arthritis,pregnancy,leucovorin', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('metoprolol', 'Metoprolol', 'Lopressor, Toprol XL', 'Cardioselective beta-1 blocker', 'Selective beta-1 adrenergic blockade lowers HR, BP, and myocardial oxygen demand.', 'Hypertension, angina, post-MI, CHF (selected), AFib rate control.', 'HR < 60, 2nd/3rd degree AV block, decompensated heart failure, asthma (relative).', 'Abrupt discontinuation may precipitate angina/MI in CAD patients.', 'Heart rate, blood pressure, glucose (may mask hypoglycemia)', 'Don''t stop abruptly. Check pulse before dose - hold if HR<60. Rise slowly.', 'Hold for HR<60 or SBP<100 unless provider says otherwise. Monitor for fatigue and depression.', 'beta_blocker,hypertension,afib,mi,bradycardia,cardiology', 'published', unixepoch())
