INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('morphine-sulfate', 'Morphine sulfate', 'MS Contin, Roxanol', 'Opioid analgesic', 'Agonist at mu-opioid receptors; inhibits pain transmission and modulates perception.', 'Acute and chronic moderate-to-severe pain, MI (vasodilator effect), palliative dyspnea.', 'Respiratory depression, paralytic ileus, severe asthma without ventilation.', 'Respiratory depression, abuse potential, accidental overdose, neonatal opioid withdrawal.', 'None routine; monitor respiratory rate + sedation scale', 'Take exactly as prescribed. Stool softener for constipation. Never mix with alcohol/benzos.', 'Antidote: naloxone. Hold for RR<12. Assess pain before/after. PCA: check basal+demand limits.', 'opioid,pain,respiratory_depression,naloxone,palliative,critical_care', 'published', unixepoch())
