INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('normal-saline', '0.9% Sodium chloride (Normal saline)', 'NS, 0.9% NaCl', 'Isotonic IV crystalloid', 'Replenishes extracellular fluid volume; matches plasma tonicity.', 'Hypovolemia, hemorrhagic shock, hyponatremia, IV access maintenance.', 'Caution with CHF, edema, hypernatremia, severe renal impairment.', NULL, 'Sodium, chloride, BUN/creatinine, hemoglobin', 'Will receive fluid via IV. Notify nurse for shortness of breath or swelling.', 'Monitor for fluid overload (crackles, JVD, edema). Hyperchloremic acidosis with large volumes.', 'iv_fluids,hypovolemia,shock,crystalloid,fluid_resuscitation,critical_care', 'published', unixepoch())
