INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('ondansetron', 'Ondansetron', 'Zofran', '5-HT3 receptor antagonist (antiemetic)', 'Selectively blocks serotonin receptors in CTZ and vagal afferents, reducing nausea signaling.', 'Chemo-induced nausea, postop nausea, hyperemesis gravidarum.', 'Congenital long QT syndrome, concurrent apomorphine.', NULL, 'EKG (QT interval), magnesium, potassium', 'Dissolves on tongue (ODT form). Report irregular heartbeat or fainting.', 'Monitor QT prolongation, especially with electrolyte imbalance. Headache and constipation common.', 'antiemetic,nausea,chemo,postop,qt_prolongation,5ht3', 'published', unixepoch())
