INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('oxytocin-ob', 'Oxytocin (OB)', 'Pitocin, Syntocinon', 'Uterotonic / posterior pituitary hormone', 'Binds oxytocin receptors on uterine smooth muscle, stimulating contractions.', 'Labor induction/augmentation, postpartum hemorrhage prevention/treatment.', 'Fetal distress, cephalopelvic disproportion, prior classic C-section, placenta previa.', 'Uterine rupture, fetal/maternal harm with improper use.', 'Sodium (water intoxication), fluid balance', 'Will cause stronger contractions. Continuous fetal monitoring required.', 'Piggyback into mainline. Titrate by uterine response. Hold for tachysystole (>5 contractions in 10 min) or non-reassuring FHR.', 'oxytocin,pitocin,labor_induction,postpartum_hemorrhage,uterine_rupture,obstetrics,maternity', 'published', unixepoch())
