INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('phenytoin', 'Phenytoin', 'Dilantin', 'Hydantoin anticonvulsant', 'Stabilizes neuronal membranes by inhibiting sodium influx, raising seizure threshold.', 'Tonic-clonic and partial seizures, status epilepticus, trigeminal neuralgia.', 'Sinus bradycardia, AV block, porphyria.', 'IV cardiovascular collapse if infused too rapidly.', 'Phenytoin level (10-20 mcg/mL), albumin, CBC, LFTs', 'Take same time daily. Good oral hygiene (gingival hyperplasia). Avoid alcohol. Don''t stop abruptly. Stevens-Johnson rash = emergency.', 'IV: max 50 mg/min, dedicated line with saline (precipitates with dextrose). Many drug interactions. Free vs total level in low albumin.', 'anticonvulsant,seizure,status_epilepticus,gingival_hyperplasia,stevens_johnson,neurology', 'published', unixepoch())
