INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('propofol', 'Propofol', 'Diprivan', 'Anesthetic - sedative-hypnotic', 'GABA-A receptor agonist; rapid loss of consciousness via global CNS depression.', 'Induction/maintenance of general anesthesia, ICU sedation.', 'Egg, soybean, or sulfite allergy. Use caution in hypotension and cardiac instability.', NULL, 'Triglycerides (with prolonged infusion), CPK, lactate, ABG', 'Will fall asleep quickly. Inform staff about egg/soy allergies. May feel groggy on wakeup.', 'Dedicated IV line. Monitor for hypotension, bradycardia, and propofol infusion syndrome. Strict aseptic technique.', 'anesthesia,sedation,icu,critical_care,hypotension', 'published', unixepoch())
