INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('sertraline', 'Sertraline', 'Zoloft', 'SSRI antidepressant', 'Selectively inhibits serotonin reuptake at the presynaptic neuronal membrane.', 'Major depressive disorder, panic, OCD, PTSD, social anxiety, PMDD.', 'MAOI use within 14 days, pimozide use.', 'Suicidality in children/adolescents/young adults; serotonin syndrome.', 'Sodium (SIADH risk), liver enzymes (baseline)', 'Takes 4-6 weeks for full effect. Don''t stop abruptly. Report mood worsening or suicidal thoughts. No alcohol.', 'Monitor for serotonin syndrome (hyperthermia, agitation, tremor, hyperreflexia). Suicide assessment, especially first 4 weeks.', 'ssri,depression,suicide,serotonin_syndrome,siadh,mental_health,psychiatric', 'published', unixepoch())
