INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('succinylcholine', 'Succinylcholine', 'Anectine, Quelicin', 'Depolarizing neuromuscular blocker', 'Acts as acetylcholine, prolonged depolarization of motor end-plate causes paralysis.', 'Rapid sequence intubation, short procedures requiring muscle relaxation.', 'Personal/family history of malignant hyperthermia, hyperkalemia, burns >24h, recent stroke or spinal cord injury.', 'Cardiac arrest in pediatric patients with undiagnosed myopathy; risk of malignant hyperthermia.', 'Potassium, CK, ABG', 'Used during intubation - you will not remember it.', 'Have dantrolene ready for malignant hyperthermia. Monitor train-of-four. Brief duration (5-10 min).', 'anesthesia,paralytic,intubation,rsi,malignant_hyperthermia,hyperkalemia', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('tacrolimus', 'Tacrolimus', 'Prograf, Astagraf', 'Calcineurin inhibitor immunosuppressant', 'Binds FKBP-12 → inhibits calcineurin → blocks T-cell activation.', 'Transplant rejection prevention (kidney, liver, heart), refractory autoimmune disease.', 'Hypersensitivity to macrolides or polyoxyl 60 hydrogenated castor oil.', 'Lymphoma + skin malignancies, severe infection, nephrotoxicity, neurotoxicity.', 'Tacrolimus trough, creatinine, potassium, glucose, magnesium', 'Same times daily, with or without food but be consistent. Avoid grapefruit. Use contraception. Report tremor, headache, weight gain.', 'Narrow therapeutic index. Monitor for new-onset diabetes, hypertension, neurotoxicity. No grapefruit/St. John''s wort.', 'immunosuppressant,transplant,nephrotoxicity,grapefruit,cyp3a4,diabetes,calcineurin', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('vancomycin', 'Vancomycin', 'Vancocin', 'Glycopeptide antibiotic', 'Inhibits gram-positive cell wall synthesis. Used for MRSA, C. diff (oral).', 'MRSA infections, severe gram-positive infections, C. difficile colitis (PO).', 'Hypersensitivity. Renal impairment requires dosing adjustment.', NULL, 'Trough levels (15-20 mcg/mL for serious infections), creatinine, hearing baseline', 'Report changes in hearing, ringing in ears, decreased urine output.', 'Infuse over at least 60 min to prevent vancomycin flushing syndrome (red man). Monitor for nephrotoxicity and ototoxicity.', 'antibiotic,mrsa,c_diff,nephrotoxicity,ototoxicity,red_man,infection', 'published', unixepoch())
ON CONFLICT(id) DO UPDATE SET generic_name = excluded.generic_name, brand_names = excluded.brand_names, drug_class = excluded.drug_class, mechanism = excluded.mechanism, indications = excluded.indications, contraindications = excluded.contraindications, black_box_warning = excluded.black_box_warning, priority_labs = excluded.priority_labs, patient_teaching = excluded.patient_teaching, nursing_implications = excluded.nursing_implications, related_tags = excluded.related_tags, publish_state = excluded.publish_state, updated_at = unixepoch();
INSERT INTO drug_cards (id, generic_name, brand_names, drug_class, mechanism, indications, contraindications, black_box_warning, priority_labs, patient_teaching, nursing_implications, related_tags, publish_state, updated_at) VALUES ('warfarin', 'Warfarin', 'Coumadin, Jantoven', 'Anticoagulant - vitamin K antagonist', 'Inhibits vitamin K-dependent clotting factors (II, VII, IX, X) and proteins C and S.', 'Long-term anticoagulation for AFib, mechanical valves, recurrent VTE.', 'Pregnancy (Category X), active bleeding, severe liver disease.', 'Fatal bleeding risk.', 'PT/INR (target 2-3 for most indications, 2.5-3.5 mechanical valves)', 'Maintain consistent vitamin K intake (greens). Avoid NSAIDs, ASA without provider OK. Carry medical ID.', 'Antidote: vitamin K (slow), FFP/PCC (urgent). Bridge with heparin/LMWH at initiation.', 'anticoagulant,afib,inr,bleeding,pregnancy,cardiology', 'published', unixepoch())
